#nullable disable

using System;
using System.Collections.Generic;
using OpenAI.Responses;

namespace Azure.AI.Extensions.OpenAI;

public partial class AzureFunctionToolCall
{
    /// <summary> Initializes a new instance of <see cref="AzureFunctionToolCall"/>. </summary>
    /// <param name="callId"> The unique ID of the tool call generated by the model. </param>
    /// <param name="name"> The name of the Azure Function being called. </param>
    /// <param name="arguments"> A JSON string of the arguments to pass to the tool. </param>
    /// <param name="status"> The status of the tool call. </param>
    public AzureFunctionToolCall(string callId, string name, string arguments, ToolCallStatus status) : base(ResponseItemKind.AzureFunctionCall)
    {
        CallId = callId;
        Name = name;
        Arguments = arguments;
        Status = status;
    }

    /// <summary> Initializes a new instance of <see cref="AzureFunctionToolCall"/>. </summary>
    /// <param name="id"></param>
    /// <param name="agentReference"> The agent that created the item. </param>
    /// <param name="responseId"> The response on which the item is created. </param>
    /// <param name="callId"> The unique ID of the tool call generated by the model. </param>
    /// <param name="name"> The name of the Azure Function being called. </param>
    /// <param name="arguments"> A JSON string of the arguments to pass to the tool. </param>
    /// <param name="status"> The status of the tool call. </param>
    /// <param name="additionalBinaryDataProperties"> Keeps track of any properties unknown to the library. </param>
    internal AzureFunctionToolCall(string id, AgentReference agentReference, string responseId, string callId, string name, string arguments, ToolCallStatus status, IDictionary<string, BinaryData> additionalBinaryDataProperties) : base(ResponseItemKind.AzureFunctionCall)
    {
        CallId = callId;
        Name = name;
        Arguments = arguments;
        Status = status;
        _additionalBinaryDataProperties = additionalBinaryDataProperties;
    }

    /// <summary> Initializes a new instance of <see cref="AzureFunctionToolCall"/> for deserialization. </summary>
    internal AzureFunctionToolCall(): base(ResponseItemKind.AzureFunctionCall)
    {
    }

    // Custom: the generated constructor passed (id, agentReference, responseId) to the
    // OpenAI ResponseItem base type, which only exposes a constructor taking the kind, causing
    // CS1729. Relocated here from the generated model and changed to call base(@type) only.
    /// <summary> Initializes a new instance of <see cref="AzureFunctionToolCall"/>. </summary>
    /// <param name="type"></param>
    /// <param name="id"></param>
    /// <param name="agentReference"> The agent that created the item. </param>
    /// <param name="responseId"> The response on which the item is created. </param>
    /// <param name="callId"> The unique ID of the tool call generated by the model. </param>
    /// <param name="name"> The name of the Azure Function being called. </param>
    /// <param name="arguments"> A JSON string of the arguments to pass to the tool. </param>
    /// <param name="status"> The status of the tool call. </param>
    /// <param name="additionalBinaryDataProperties"> Keeps track of any properties unknown to the library. </param>
    internal AzureFunctionToolCall(ResponseItemKind @type, string id, AgentReference agentReference, string responseId, string callId, string name, string arguments, ToolCallStatus status, IDictionary<string, BinaryData> additionalBinaryDataProperties) : base(@type)
    {
        CallId = callId;
        Name = name;
        Arguments = arguments;
        Status = status;
        _additionalBinaryDataProperties = additionalBinaryDataProperties;
    }
}
